"use strict";parserFactory.register("chickengege.org",()=>new ChickengegeParser);class ChickengegeParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector("ul#novelList, ul#extraList, table#novelList");return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector("article div.entry-content")}extractTitleImpl(e){return e.querySelector("h1.entry-title")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,".m-a-box, .m-a-box-container"),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector("h1.entry-title")}preprocessRawDom(e){let t=this.findContent(e),r=this.extractFootnotes(e);this.moveFootnotes(e,t,r)}extractFootnotes(e){return[...e.querySelectorAll("script")].filter(e=>e.textContent.includes("{ toolTips(")).map(t=>this.scriptToSpan(t,e))}scriptToSpan(e,t){let r=t.createElement("span");return r.textContent=this.extractFootnoteText(e),r}extractFootnoteText(e){let t=e.textContent.replace('jQuery("document")',""),r=t.indexOf('"')+1,n=t.lastIndexOf("\",'");return t.substring(r,n)}}